params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_用件確認 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"歯科口腔外科": "1", "健康管理センター": "1", "インフルエンザワクチン": "1", "コロナウイルスワクチン": "1", "対応外診療科": "1", "予約": "1", "変更": "1", "キャンセル": "1", "確認": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_用件確認");
var mapping = {"歯科口腔外科": "1", "健康管理センター": "1", "インフルエンザワクチン": "1", "コロナウイルスワクチン": "1", "対応外診療科": "1", "予約": "1", "変更": "1", "キャンセル": "1", "確認": "1"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);
